#!/usr/bin/env node
// Auto-generated by the Force1 VSCode extension. Do not edit by hand —
// changes will be overwritten on the next plugin activation.
//
// Usage: node force1-hook.js <event-name>
//   <event-name> is the Claude Code hook event (post-tool-use,
//   user-prompt-submit, stop, session-start, ...). The hook payload arrives
//   as JSON on stdin.

"use strict";

const fs = require("fs");
const path = require("path");
const http = require("http");

const event = process.argv[2] || "unknown";

// Find .force1/state.json by walking up from cwd. Hooks normally fire from
// the workspace root, but be defensive in case Claude Code chdir's elsewhere.
function findStateFile(start) {
  let dir = path.resolve(start);
  for (let i = 0; i < 8; i++) {
    const candidate = path.join(dir, ".force1", "state.json");
    if (fs.existsSync(candidate)) return candidate;
    const parent = path.dirname(dir);
    if (parent === dir) return null;
    dir = parent;
  }
  return null;
}

function readStdin() {
  return new Promise((resolve) => {
    if (process.stdin.isTTY) return resolve("");
    let buf = "";
    process.stdin.setEncoding("utf-8");
    process.stdin.on("data", (chunk) => { buf += chunk; });
    process.stdin.on("end", () => resolve(buf));
    process.stdin.on("error", () => resolve(buf));
  });
}

(async () => {
  try {
    const stateFile = findStateFile(process.cwd());
    if (!stateFile) {
      // Extension isn't running or hasn't activated yet — silently skip so
      // we don't block Claude Code.
      process.exit(0);
    }
    const state = JSON.parse(fs.readFileSync(stateFile, "utf-8"));
    if (!state || typeof state.port !== "number") process.exit(0);

    const stdin = await readStdin();
    let payload = null;
    if (stdin.trim()) {
      try { payload = JSON.parse(stdin); } catch { payload = { raw: stdin }; }
    }

    // Forward the FORCE1_AGENT env var (set by the extension when it spawns
    // Claude Code for a Force1 Build) so the session collector can distinguish
    // Force1-initiated sessions from ad-hoc ones and skip review-epic
    // synthesis for the former.
    const force1Agent = process.env.FORCE1_AGENT || null;
    const body = JSON.stringify({ event, payload, force1Agent, ts: new Date().toISOString() });
    const req = http.request({
      host: "127.0.0.1",
      port: state.port,
      method: "POST",
      path: "/event/" + encodeURIComponent(event),
      headers: {
        "Content-Type": "application/json",
        "Content-Length": Buffer.byteLength(body),
        "X-Force1-Token": String(state.token || ""),
      },
      timeout: 800,
    });
    req.on("error", () => process.exit(0));
    req.on("timeout", () => { req.destroy(); process.exit(0); });
    req.write(body);
    req.end();
    // Don't wait for response — fire and forget.
    req.on("response", (res) => { res.resume(); res.on("end", () => process.exit(0)); });
  } catch {
    process.exit(0);
  }
})();
